svg.script:

const challenges = [
  {
    title: "Weak Engines",
    lines: [
      "Early engines were too heavy and produced too little power.",
      "They could not spin a rotor fast enough to generate lift.",
      "Power-to-weight ratio was the single biggest barrier.",
      "The internal combustion engine finally made flight possible."
    ]
  },
  {
    title: "Heavy Materials",
    lines: [
      "Strong but lightweight materials simply did not exist.",
      "Wood and fabric were light but not strong enough.",
      "Metal was strong but added too much weight.",
      "Every gram mattered — early designs had tiny margins."
    ]
  },
  {
    title: "Poor Control",
    lines: [
      "Getting a model to lift off was one thing; steering it was another.",
      "There were no reliable control surfaces or feedback systems.",
      "Pilots could not counter drift, tilt, or sudden gusts.",
      "Autogyros later helped prove that controlled rotary flight was possible."
    ]
  },
  {
    title: "Torque & Stability",
    lines: [
      "When the main rotor spins, the fuselage wants to spin the opposite way.",
      "This is Newton's Third Law: every action has an equal and opposite reaction.",
      "Solutions included tail rotors, coaxial rotors, and NOTAR systems.",
      "Solving torque was essential for stable, controlled flight."
    ]
  }
];

function initChallenges() {
  selectChallenge(0);
}

function selectChallenge(index) {
  // Update tabs
  for (let i = 0; i < 4; i++) {
    const tab = document.getElementById('tab-' + i);
    if (i === index) {
      tab.classList.add('active');
    } else {
      tab.classList.remove('active');
    }
  }

  // Update highlights
  for (let i = 0; i < 4; i++) {
    const hl = document.getElementById('hl-' + i);
    const icon = document.getElementById('icon-' + i);
    if (hl) hl.classList.remove('active');
    if (icon) icon.setAttribute('opacity', '0');
  }
  const hl3a = document.getElementById('hl-3a');
  const hl3b = document.getElementById('hl-3b');
  if (hl3a) hl3a.classList.remove('active');
  if (hl3b) hl3b.classList.remove('active');

  if (index === 3) {
    if (hl3a) hl3a.classList.add('active');
    if (hl3b) hl3b.classList.add('active');
  } else {
    const hl = document.getElementById('hl-' + index);
    if (hl) hl.classList.add('active');
  }
  const icon = document.getElementById('icon-' + index);
  if (icon) icon.setAttribute('opacity', '1');

  // Torque arrow
  const arrow = document.getElementById('arrow-torque');
  const arrowText = document.getElementById('text-torque');
  if (arrow) arrow.classList.toggle('active', index === 3);
  if (arrowText) arrowText.classList.toggle('active', index === 3);

  // Update info panel
  const c = challenges[index];
  document.getElementById('info-title').textContent = c.title;
  for (let i = 0; i < 4; i++) {
    const lineEl = document.getElementById('info-line-' + (i + 1));
    if (lineEl) lineEl.textContent = c.lines[i] || '';
  }
}
